import{_ as t,o as r,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"27. Transition To Retirement","description":"","frontmatter":{"title":"27. Transition To Retirement","eba":"Health Allied & Managers Admin 2021-2025","topics":["preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/employment-types/27-transition-to-retirement.md","filePath":"ebas/has-managers-admin/common-terms/employment-types/27-transition-to-retirement.md"}'),n={name:"ebas/has-managers-admin/common-terms/employment-types/27-transition-to-retirement.md"};function i(s,e,p,l,m,h){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_27-transition-to-retirement" tabindex="-1">27. Transition To Retirement <a class="header-anchor" href="#_27-transition-to-retirement" aria-label="Permalink to &quot;27. Transition To Retirement&quot;">​</a></h1><p><strong>27.1</strong> Employees may advise their Employer in writing of their intention to retire within the next five years from their Employer and may participate in a transition to retirement arrangement. Subject to this Agreement, a transition to retirement arrangement is a permanent arrangement that is agreed between the Employee and the Employer.</p><p><strong>27.2</strong> Transition to retirement arrangements may be proposed. The Employer will provide details of the proposal for the Employee’s consideration including any relevant information (including indicative changes to pay) about the implications of the proposal. The Employee will be given a reasonable opportunity to consider the proposal. Employees are encouraged to seek advice regarding the proposal.</p><p><strong>27.3</strong> Where a transition to retirement arrangement is agreed, it will be implemented through:</p><p><strong>(a)</strong> a flexible working arrangement (see <a href="/eba/ebas/has-managers-admin/common-terms/classification-staffing/79-requests-for-flexible-working-arrangements.html">clause 79</a>);</p><p><strong>(b)</strong> an individual flexibility agreement (see <a href="/eba/ebas/has-managers-admin/common-terms/preliminary/13-individual-flexibility-arrangement.html">clause 13</a>);</p><p><strong>(c)</strong> an agreement in writing between the parties; or</p><p><strong>(d)</strong> any combination of the above.</p><p><strong>27.4</strong> A transition to retirement arrangement may include but is not limited to:</p><p><strong>(a)</strong> alteration of working hours, e.g. part-time employment, shift pattern;</p><p><strong>(b)</strong> a job share arrangement;</p><p>PART C – TYPES OF EMPLOYMENT AND TERMINATION OF EMPLOYMENT</p><p><strong>(c)</strong> working in a position at a lower status or rate of pay;</p><p><strong>(d)</strong> flexible use of Long Service Leave (LSL)</p><p><strong>27.5</strong> The Employer will consider, and not unreasonably withhold its approval of a request by an Employee to transition to retirement through:</p><p><strong>(a)</strong> using accrued LSL or Annual Leave for the purpose of reducing the number of days worked or their working hours but retaining their previous employment status</p><p>Examples: 1. A full-time Employee may work 3 days per week and have 2 days of accrued long service leave per week, retaining their full-time status. 2. A part-time Employee employed for 24 hours per week may work 20 hours per week and take 4 hours of accrued annual leave per week, retaining their status as a part-time Employee employed for 24 hours per week.</p><p>or;</p><p><strong>(b)</strong> accepting appointment to a role that has a lower hourly rate of pay and/or reduced hours (post transition role), in which case:</p><p><strong>(i)</strong> the Employee will retain the accrual of LSL they had immediately prior to the reduction in their rate of pay and/or hours (preserved LSL). Where LSL is taken, the Employee will be paid LSL hours at the wage rate and/or their hours of work prior to the post transition role until the preserved LSL hours exhausted;</p><p>Examples: 1. An Employee’s hourly rate of pay is reduced under this subclause (b)from $35 to $30. When the Employee takes LSL their LSL will be paid at the rate of $35 per hour until the preserved LSL is exhausted. 2. An Employee’s hours of work are reduced under this subclause</p><p><strong>(b)</strong> from 32 hours per week to 24 hours per week. When the Employee takes LSL they will be paid for 32 hours of LSL per week until the preserved LSL is exhausted. 3. An Employee’s hourly rate of pay is reduced under this subclause (b) from $40 to $35 and their hours of work from 38 to 30 hours per week. When the Employee takes LSL it will be paid at the rate of $40 per hour and they will be paid for 38 hours of LSL per week until the preserved LSL is exhausted.</p><p><strong>(ii)</strong> however, if the Employee&#39;s hourly wage rate in the post- transition role over time exceeds the wage rate of the pre-</p><p>PART C – TYPES OF EMPLOYMENT AND TERMINATION OF EMPLOYMENT</p><p>transition role, the higher wage rate will be used to calculate LSL.</p><p>PART D - WAGES</p><p>Plain language terms: phased retirement, winding down, TTR.</p>',27)])])}const u=t(n,[["render",i]]);export{g as __pageData,u as default};
